from collections import defaultdict

def solve(n: int, edges: list[list[int]], label: str) -> int:
    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    max_len = 1

    def backtrack(current_path, visited):
        nonlocal max_len
        m = len(current_path)
        is_pal = True
        for i in range(m // 2):
            if label[current_path[i]] != label[current_path[m - 1 - i]]:
                is_pal = False
                break
        if is_pal:
            max_len = max(max_len, m)

        last_node = current_path[-1]
        for neighbor in graph[last_node]:
            if not (visited & (1 << neighbor)):
                new_visited = visited | (1 << neighbor)
                backtrack(current_path + [neighbor], new_visited)

    for start in range(n):
        backtrack([start], 1 << start)

    return max_len
