from typing import List
from collections import defaultdict

def solve(n: int, edges: List[List[int]], label: str) -> int:
    adj = defaultdict(list)
    for u, v in edges:
        adj[u].append(v)
        adj[v].append(u)

    max_len = 0

    def is_palindrome(path_labels):
        k = len(path_labels)
        for i in range(k // 2):
            if path_labels[i] != path_labels[k - 1 - i]:
                return False
        return True

    def dfs(node, visited_mask, path_labels):
        nonlocal max_len
        if is_palindrome(path_labels):
            max_len = max(max_len, len(path_labels))
        for neighbor in adj[node]:
            if not (visited_mask & (1 << neighbor)):
                new_visited_mask = visited_mask | (1 << neighbor)
                new_path = path_labels + [label[neighbor]]
                dfs(neighbor, new_visited_mask, new_path)

    for start in range(n):
        visited_mask = 1 << start
        path_labels = [label[start]]
        dfs(start, visited_mask, path_labels)

    return max_len
